HTML = open(__file__[:-3]+"_index.html", encoding="utf-8").read()
JS   = open(__file__[:-3]+"_bundle.js", encoding="utf-8").read()

@app.route("/")
@app.route("/index.html")
def index():
    return Response(HTML, mimetype="text/html")

@app.route("/assets/<path:name>")
def assets(name):
    return Response(JS, mimetype="application/javascript")

@app.route("/dashboard_config.json")
def cfg():
    return jsonify({"api_base_url": "", "market": "US"})

@app.route("/api/health")
def health():
    return jsonify({"service":"stock_rtx4060_unified","status":"ok","version":"5.0.0"})

@app.route("/api/universe")
def universe():
    market = request.args.get("market","US")
    syms = UNIVERSE.get(market, UNIVERSE["US"])
    return jsonify({"market":market,"symbols":syms,"count":len(syms),"source":"backend_config"})

@app.route("/api/symbol")
def symbol():
    sym = request.args.get("symbol","AAPL").upper()
    rows = OHLCV.get(sym, OHLCV["AAPL"])
    last = rows[-1]
    prev = rows[-2]["close"]
    chg = round(last["close"]-prev, 2)
    chg_pct = round((chg/prev)*100, 2)
    return jsonify({
        "symbol": sym, "provider": "synthetic", "source": "SYNTHETIC_DEMO",
        "last_close": last["close"], "last_date": last["date"],
        "change": chg, "change_pct": chg_pct, "data": rows,
    })

@app.route("/api/model-scores")
def model_scores():
    sym = request.args.get("symbol","AAPL").upper()
    random.seed(hash(sym) % 9999)
    score = round(45 + random.random()*35, 1)
    verdict = "AMBER_REVIEW_ONLY" if score >= 55 else "RED_NOT_RECOMMENDED"
    return jsonify({
        "symbol": sym, "verdict": verdict, "score": score,
        "track_s": {"score": score, "verdict": verdict},
        "track_l": {"score": round(score-5,1), "verdict": "RED_NOT_RECOMMENDED"},
        "backtest": {"sharpe": round(random.random()*1.5,2),
                     "total_return_pct": round((random.random()-0.2)*50,1),
                     "max_drawdown_pct": round(random.random()*25,1),
                     "win_rate": round(0.4+random.random()*0.25,2),
                     "n_trades": random.randint(20,80)},
        "model_proba": round(0.3+random.random()*0.4,3),
        "oof_auc": round(0.5+random.random()*0.2,3),
    })

@app.route("/api/paper-status")
def paper_status():
    return jsonify({"status":"no_paper_trades","positions":{},"pnl_total":0,
                    "note":"Paper trading not active"})

@app.route("/api/recommend")
def recommend():
    return jsonify({"candidates":[],"schema_version":"dashboard_snapshot.v1",
                    "note":"Run locally with full dependencies for recommendations"})

if __name__ == "__main__":
    import threading
    import time
    import webbrowser
    def _open():
        time.sleep(1.5)
        webbrowser.open("http://localhost:5151")
    threading.Thread(target=_open, daemon=True).start()
    print("\n  STOCK·PRED v5.0 Dashboard")
    print("  Open: http://localhost:5151\n")
    app.run(host="0.0.0.0", port=5151, debug=False)
